#!/usr/bin/env node
// Syncs .claude/ → templates/.claude/ before every npm publish.
// Excludes: settings.local.json, logs/, specs/, outputs/, .DS_Store, symlinks in agents/ root
// (symlinks are regenerated by the consumer via `rstack-agents init`).

import { cpSync, rmSync, mkdirSync, existsSync, lstatSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { readdirSync } from 'node:fs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');
const src = join(root, '.claude');
const dest = join(root, 'templates', '.claude');

const EXCLUDE = new Set([
  'settings.local.json',
  '.DS_Store',
  'logs',
  'specs',
  'outputs',
]);

function isSymlink(p) {
  try { return lstatSync(p).isSymbolicLink(); } catch { return false; }
}

function shouldExclude(name, fullPath) {
  if (EXCLUDE.has(name)) return true;
  // Skip symlinks in agents/ root (flat discovery layer — regenerated on install)
  if (fullPath.includes(`${src}/agents/`) && !fullPath.includes(`${src}/agents/core`) &&
      !fullPath.includes(`${src}/agents/sdlc`) && !fullPath.includes(`${src}/agents/specialists`) &&
      isSymlink(fullPath)) return true;
  return false;
}

function copyDir(from, to) {
  mkdirSync(to, { recursive: true });
  for (const entry of readdirSync(from, { withFileTypes: true })) {
    const srcPath = join(from, entry.name);
    const destPath = join(to, entry.name);
    if (shouldExclude(entry.name, srcPath)) continue;
    if (entry.isSymbolicLink()) continue; // skip all symlinks in templates
    if (entry.isDirectory()) {
      copyDir(srcPath, destPath);
    } else {
      cpSync(srcPath, destPath);
    }
  }
}

console.log('[rstack] Syncing .claude/ → templates/.claude/ ...');
if (existsSync(dest)) rmSync(dest, { recursive: true, force: true });
copyDir(src, dest);
console.log('[rstack] templates/.claude/ ready for publish.');
